number_of_employees: 21
founded_year: 2006
score: 2.0815043449401855
source: "companies"

name: "Pulse Mobile"
number_of_employees: null
founded_year: null
score: 2.0815043449401855
source: "companies"

name: "T-Mobile"
number_of_employees: null
founded_year: null
score: 2.0815043449401855
source: "companies"

business_name: "T. MOBILE"
address: Object
